const item = $input.first().json;

const busyPeriods = item.calendars?.['fabiohhsales@gmail.com']?.busy || [];
const timeWindowHint = (item.window_hint || '').toLowerCase();

const SLOTS_HORARIOS = [9, 11, 13, 17];
const MAX_SLOTS = 3;
const DIAS = ['Domingo','Segunda-feira','Terça-feira','Quarta-feira',
              'Quinta-feira','Sexta-feira','Sábado'];

const MESES = {
  'janeiro':0,'fevereiro':1,'março':2,'marco':2,'abril':3,
  'maio':4,'junho':5,'julho':6,'agosto':7,'setembro':8,
  'outubro':9,'novembro':10,'dezembro':11
};

const busy = busyPeriods.map(b => ({
  start: new Date(b.start),
  end: new Date(b.end)
}));

// Filtro de período
function periodFilter(hora) {
  if (timeWindowHint.includes('manhã')) return hora < 12;
  if (timeWindowHint.includes('tarde') && !timeWindowHint.includes('noite')) return hora >= 13 && hora < 17;
  if (timeWindowHint.includes('noite') || timeWindowHint.includes('início da noite')) return hora >= 17;
  if (timeWindowHint.includes('tarde') && timeWindowHint.includes('noite')) return hora >= 13;
  return true;
}

function isAvailable(start, end) {
  return !busy.some(b => start < b.end && end > b.start);
}

// Calcula data de início baseado no hint
function calcWindowStart(hint) {
  const hoje = new Date();
  hoje.setHours(0,0,0,0);

  // Detecta "semana de DD/MM"
  const semanaMatch = hint.match(/semana\s+de\s+(\d{1,2})\/(\d{1,2})/);
  if (semanaMatch) {
    const ano = new Date().getFullYear();
    const d = parseInt(semanaMatch[1]);
    const m = parseInt(semanaMatch[2]) - 1;
    const anchor = new Date(ano, m, d);
    // Se já passou, vai pro próximo ano
    if (anchor < hoje) anchor.setFullYear(ano + 1);
    return anchor;
  }

  // Detecta mês por extenso: "início de março", "começo de abril", etc.
  for (const [nome, idx] of Object.entries(MESES)) {
    if (hint.includes(nome)) {
      const ano = new Date().getFullYear();
      let mesAlvo = new Date(ano, idx, 1);
      if (mesAlvo < hoje) mesAlvo = new Date(ano + 1, idx, 1);

      if (hint.includes('início') || hint.includes('começo')) {
        return new Date(mesAlvo.getFullYear(), mesAlvo.getMonth(), 1);
      }
      if (hint.includes('meio') || hint.includes('metade')) {
        return new Date(mesAlvo.getFullYear(), mesAlvo.getMonth(), 15);
      }
      if (hint.includes('fim') || hint.includes('final')) {
        return new Date(mesAlvo.getFullYear(), mesAlvo.getMonth(), 20);
      }
      return mesAlvo;
    }
  }

  // Detecta "semana que vem" / "próxima semana"
  if (hint.includes('semana que vem') || hint.includes('próxima semana')) {
    const diasAteSeg = (8 - hoje.getDay()) % 7 || 7;
    const seg = new Date(hoje);
    seg.setDate(hoje.getDate() + diasAteSeg);
    return seg;
  }

  // Detecta "essa semana" / "esta semana"
  if (hint.includes('essa semana') || hint.includes('esta semana')) {
    return new Date(hoje.getTime() + 86400000); // amanhã
  }

  // Padrão: amanhã
  return new Date(hoje.getTime() + 86400000);
}

// Define janela de busca
const windowStart = calcWindowStart(timeWindowHint);
windowStart.setHours(0,0,0,0);
const windowEnd = new Date(windowStart);
windowEnd.setDate(windowStart.getDate() + 14);

const freeSlots = [];

for (let d = 0; d <= 14; d++) {
  if (freeSlots.length >= MAX_SLOTS) break;

  const dia = new Date(windowStart);
  dia.setDate(windowStart.getDate() + d);
  dia.setHours(0,0,0,0);

  if (dia > windowEnd) break;

  const dow = dia.getDay();
  if (dow === 0 || dow === 6) continue;

  for (const hora of SLOTS_HORARIOS) {
    if (freeSlots.length >= MAX_SLOTS) break;
    if (!periodFilter(hora)) continue;

    const slotStart = new Date(dia);
    slotStart.setHours(hora, 0, 0, 0);

    const slotEnd = new Date(dia);
    slotEnd.setHours(hora + 1, 0, 0, 0);

    if (slotEnd.getHours() > 18) continue;
    if (!isAvailable(slotStart, slotEnd)) continue;

    const dd = String(slotStart.getDate()).padStart(2,'0');
    const mm = String(slotStart.getMonth() + 1).padStart(2,'0');

    freeSlots.push({
      display: `*${freeSlots.length + 1}.* ${DIAS[dow]}, ${dd}/${mm} às ${hora.toString().padStart(2,'0')}:00 – ${(hora+1).toString().padStart(2,'0')}:00`,
      start_iso: slotStart.toISOString(),
      end_iso: slotEnd.toISOString()
    });
  }
}

const slotsFormatted = freeSlots.length > 0
  ? `📅 Encontrei ${freeSlots.length} horário${freeSlots.length > 1 ? 's disponíveis' : ' disponível'} pra você:\n\n` +
    freeSlots.map(s => s.display).join('\n') +
    '\n\nQual dessas opções funciona melhor pra você?'
  : 'Não encontrei horários disponíveis no período solicitado. Vou verificar com a equipe e te retorno em breve.';

return [{
  json: {
    ...item,
    availability: {
      slots: freeSlots,
      slots_formatted: slotsFormatted,
      total_found: freeSlots.length,
      window_hint: timeWindowHint,
      window_start_calculated: windowStart.toISOString()
    }
  }
}];

// n8n Code node (JavaScript)
// Objetivo: transformar item.json.output (string JSON) em campos separados no item.json

function safeJsonParse(maybeJson) {
  if (maybeJson == null) return { ok: false, error: "output is null/undefined", value: null };

  // Se já veio como objeto, só retorna
  if (typeof maybeJson === "object") {
    return { ok: true, error: null, value: maybeJson };
  }

  if (typeof maybeJson !== "string") {
    return { ok: false, error: `output is not string/object, got ${typeof maybeJson}`, value: null };
  }

  // Tenta limpar casos comuns: markdown ```json ... ```
  let s = maybeJson.trim();
  s = s.replace(/^```(?:json)?/i, "").replace(/```$/, "").trim();

  // Tenta achar o primeiro { e o último } (caso tenha texto extra)
  const first = s.indexOf("{");
  const last = s.lastIndexOf("}");
  if (first !== -1 && last !== -1 && last > first) {
    s = s.slice(first, last + 1);
  }

  try {
    return { ok: true, error: null, value: JSON.parse(s) };
  } catch (e) {
    return { ok: false, error: e.message, value: null, raw: s };
  }
}

return items.map((item) => {
  const parsed = safeJsonParse(item.json.output);

  // Se falhar, não derruba: devolve item com debug do erro
  if (!parsed.ok) {
    return {
      json: {
        ...item.json,
        _parser_ok: false,
        _parser_error: parsed.error,
        _parser_raw: parsed.raw ?? item.json.output ?? null,
      },
    };
  }

  // Sucesso: "explode" os campos do JSON dentro do item
  // Mantém o original em _raw_output se você quiser auditar depois
  return {
    json: {
      ...item.json,
      ...parsed.value,
      _parser_ok: true,
      _raw_output: item.json.output,
    },
  };
});

const ALLOWED_STATUS = new Set(["pending", "open", "resolved"]);
const ALLOWED_INTENTS = new Set(["triagem", "qualificacao", "agendamento", "confirmacao", "pos", "humano", "outro"]);

function clean(s) {
  if (typeof s !== "string") return s;
  let t = s.trim();
  t = t.replace(/^```(?:json)?/i, "").replace(/```$/i, "").trim();
  // corta do primeiro { ao último }
  const first = t.indexOf("{");
  const last = t.lastIndexOf("}");
  if (first !== -1 && last !== -1 && last > first) t = t.slice(first, last + 1);
  return t;
}

function safeParse(str) {
  if (str == null) return { ok: false, error: "output is null/undefined", value: null };
  if (typeof str === "object") return { ok: true, error: null, value: str };
  if (typeof str !== "string") return { ok: false, error: `output is ${typeof str}`, value: null };

  const s = clean(str);
  try {
    return { ok: true, error: null, value: JSON.parse(s), raw: s };
  } catch (e) {
    return { ok: false, error: e.message, value: null, raw: s };
  }
}

function ensure(obj, path, fallback) {
  // cria caminho se faltar
  const parts = path.split(".");
  let cur = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const k = parts[i];
    if (cur[k] == null || typeof cur[k] !== "object") cur[k] = {};
    cur = cur[k];
  }
  const last = parts[parts.length - 1];
  if (cur[last] === undefined) cur[last] = fallback;
}

return items.map((item) => {
  const parsed = safeParse(item.json.output);

  if (!parsed.ok) {
    return {
      json: {
        ...item.json,
        _parser_ok: false,
        _parser_error: parsed.error,
        _parser_raw: parsed.raw ?? item.json.output ?? null,
      },
    };
  }

  const o = parsed.value;

  // defaults essenciais
  if (!ALLOWED_STATUS.has(o.status_next)) o.status_next = "pending";
  if (!Array.isArray(o.labels_next) || o.labels_next.length < 1) o.labels_next = ["etapa_triagem"];

  ensure(o, "handoff", {});
  ensure(o, "handoff.needs_human", false);
  ensure(o, "handoff.reason", "");

  ensure(o, "actions", {});
  ensure(o, "actions.agenda_check", {});
  ensure(o, "actions.agenda_check.should_check", false);
  ensure(o, "actions.agenda_check.time_window_hint", null);

  ensure(o, "actions.agenda_create", {});
  ensure(o, "actions.agenda_create.should_create", false);
  ensure(o, "actions.agenda_create.start_iso", null);
  ensure(o, "actions.agenda_create.end_iso", null);
  ensure(o, "actions.agenda_create.title", null);

  // adiciona debug se estiver faltando (seu caso)
  ensure(o, "debug", {});
  ensure(o, "debug.detected_intent", "outro");
  if (!ALLOWED_INTENTS.has(o.debug.detected_intent)) o.debug.detected_intent = "outro";
  ensure(o, "debug.stage_current", null);
  ensure(o, "debug.notes", null);

  // regra hard
  if (o.handoff.needs_human === true) {
    o.status_next = "open";
    o.reply = null;
    // opcional: marca intent
    o.debug.detected_intent = "humano";
  }

  return {
    json: {
      ...item.json,
      ...o,                  // explode no item
      _parser_ok: true,
      _parser_error: null,
      _raw_output: item.json.output,
    },
  };
});

const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c == 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

return {
  id: uuid
};

