// Objetivo: transformar item.json.output (string JSON) em campos separados no item.json

function safeJsonParse(maybeJson) {
  if (maybeJson == null) return { ok: false, error: "output is null/undefined", value: null };

  // Se já veio como objeto, só retorna
  if (typeof maybeJson === "object") {
    return { ok: true, error: null, value: maybeJson };
  }

  if (typeof maybeJson !== "string") {
    return { ok: false, error: `output is not string/object, got ${typeof maybeJson}`, value: null };
  }

  // Tenta limpar casos comuns: markdown ```json ... ```
  let s = maybeJson.trim();
  s = s.replace(/^```(?:json)?/i, "").replace(/```$/, "").trim();

  // Tenta achar o primeiro { e o último } (caso tenha texto extra)
  const first = s.indexOf("{");
  const last = s.lastIndexOf("}");
  if (first !== -1 && last !== -1 && last > first) {
    s = s.slice(first, last + 1);
  }

  try {
    return { ok: true, error: null, value: JSON.parse(s) };
  } catch (e) {
    return { ok: false, error: e.message, value: null, raw: s };
  }
}

return items.map((item) => {
  const parsed = safeJsonParse(item.json.output);

  // Se falhar, não derruba: devolve item com debug do erro
  if (!parsed.ok) {
    return {
      json: {
        ...item.json,
        _parser_ok: false,
        _parser_error: parsed.error,
        _parser_raw: parsed.raw ?? item.json.output ?? null,
      },
    };
  }

  // Sucesso: "explode" os campos do JSON dentro do item
  // Mantém o original em _raw_output se você quiser auditar depois
  return {
    json: {
      ...item.json,
      ...parsed.value,
      _parser_ok: true,
      _raw_output: item.json.output,
    },
  };
});

const ALLOWED_STATUS = new Set(["pending", "open", "resolved"]);
const ALLOWED_INTENTS = new Set(["triagem", "qualificacao", "agendamento", "confirmacao", "pos", "humano", "outro"]);

function clean(s) {
  if (typeof s !== "string") return s;
  let t = s.trim();
  t = t.replace(/^```(?:json)?/i, "").replace(/```$/i, "").trim();
  // corta do primeiro { ao último }
  const first = t.indexOf("{");
  const last = t.lastIndexOf("}");
  if (first !== -1 && last !== -1 && last > first) t = t.slice(first, last + 1);
  return t;
}

function safeParse(str) {
  if (str == null) return { ok: false, error: "output is null/undefined", value: null };
  if (typeof str === "object") return { ok: true, error: null, value: str };
  if (typeof str !== "string") return { ok: false, error: `output is ${typeof str}`, value: null };

  const s = clean(str);
  try {
    return { ok: true, error: null, value: JSON.parse(s), raw: s };
  } catch (e) {
    return { ok: false, error: e.message, value: null, raw: s };
  }
}

function ensure(obj, path, fallback) {
  // cria caminho se faltar
  const parts = path.split(".");
  let cur = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const k = parts[i];
    if (cur[k] == null || typeof cur[k] !== "object") cur[k] = {};
    cur = cur[k];
  }
  const last = parts[parts.length - 1];
  if (cur[last] === undefined) cur[last] = fallback;
}

return items.map((item) => {
  const parsed = safeParse(item.json.output);

  if (!parsed.ok) {
    return {
      json: {
        ...item.json,
        _parser_ok: false,
        _parser_error: parsed.error,
        _parser_raw: parsed.raw ?? item.json.output ?? null,
      },
    };
  }

  const o = parsed.value;

  // defaults essenciais
  if (!ALLOWED_STATUS.has(o.status_next)) o.status_next = "pending";
  if (!Array.isArray(o.labels_next) || o.labels_next.length < 1) o.labels_next = ["etapa_triagem"];

  ensure(o, "handoff", {});
  ensure(o, "handoff.needs_human", false);
  ensure(o, "handoff.reason", "");

  ensure(o, "actions", {});
  ensure(o, "actions.agenda_check", {});
  ensure(o, "actions.agenda_check.should_check", false);
  ensure(o, "actions.agenda_check.time_window_hint", null);

  ensure(o, "actions.agenda_create", {});
  ensure(o, "actions.agenda_create.should_create", false);
  ensure(o, "actions.agenda_create.start_iso", null);
  ensure(o, "actions.agenda_create.end_iso", null);
  ensure(o, "actions.agenda_create.title", null);

  // adiciona debug se estiver faltando (seu caso)
  ensure(o, "debug", {});
  ensure(o, "debug.detected_intent", "outro");
  if (!ALLOWED_INTENTS.has(o.debug.detected_intent)) o.debug.detected_intent = "outro";
  ensure(o, "debug.stage_current", null);
  ensure(o, "debug.notes", null);

  // regra hard
  if (o.handoff.needs_human === true) {
    o.status_next = "open";
    o.reply = null;
    // opcional: marca intent
    o.debug.detected_intent = "humano";
  }

  return {
    json: {
      ...item.json,
      ...o,                  // explode no item
      _parser_ok: true,
      _parser_error: null,
      _raw_output: item.json.output,
    },
  };
});
